// Authoritative server simulation loop
let tick = 0;
const inputs: Input[] = [];

function simLoop() {
  const snapshot = applyPhysics(world, inputs.splice(0));
  broadcastDelta(clients, diff(previous, snapshot));
  previous = snapshot;
  tick++;
}
setInterval(simLoop, 1000 / 60); // 60 Hz
